@app.route('/mfa/backup-codes/regenerate', methods=['POST'])
@login_required
def regenerate_backup_codes():
    """Regenerate backup codes. Requires current MFA code or password."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = session.get('user_email')
    user = users_db.get(email)

    if not user:
        return jsonify({'error': 'User not found'}), 404

    if not user['mfa_enabled']:
        return jsonify({'error': 'MFA is not enabled'}), 400

    # Verify identity with either MFA code or password
    mfa_code = data.get('code', '').strip()
    password = data.get('password', '')

    verified = False
    if mfa_code:
        totp = pyotp.TOTP(user['mfa_secret'])
        if totp.verify(mfa_code, valid_window=1):
            verified = True
    if password and check_password_hash(user['password_hash'], password):
        verified = True

    if not verified:
        return jsonify({'error': 'Identity verification failed. Provide valid MFA code or password.'}), 401

    backup_codes = [secrets.token_hex(4).upper() for _ in range(10)]
    user['mfa_backup_codes'] = backup_codes

    return jsonify({
        'message': 'Backup codes regenerated successfully.',
        'backup_codes': backup_codes,
        'warning': 'Previous backup codes are now invalid. Save these securely.'
    }), 200


@app.route('/reset-mfa', methods=['POST'])
def reset_mfa_request():
    """
    Request MFA reset via email. Sends a reset link to the registered email.
    This is the account recovery entry point for users who lost MFA access.
    """
    cleanup_expired_tokens()

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = data.get('email', '').strip().lower()
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Always return success to prevent email enumeration
    success_message = (
        'If an account with that email exists and has MFA enabled, '
        'a reset link has been sent to the registered email address. '
        'The link will expire in 15 minutes.'
    )

    user = users_db.get(email)
    if not user:
        # Don't reveal that the user doesn't exist
        return jsonify({'message': success_message}), 200

    if not user['mfa_enabled']:
        # Don't reveal MFA status
        return jsonify({'message': success_message}), 200

    # Rate limiting: check for existing non-expired tokens for this email
    existing_tokens = [
        t for t, d in mfa_reset_tokens.items()
        if d['email'] == email and d['expires_at'] > datetime.utcnow()
    ]
    if len(existing_tokens) >= 3:
        # Too many pending reset requests
        return jsonify({
            'message': success_message,
            'note': 'Please check your email for previously sent links.'
        }), 200

    # Generate reset token
    token = generate_reset_token()
    mfa_reset_tokens[token] = {
        'email': email,
        'user_id': user['id'],
        'created_at': datetime.utcnow(),
        'expires_at': datetime.utcnow() + timedelta(minutes=15),
        'used': False
    }

    # Build reset link
    reset_link = url_for('confirm_mfa_reset', token=token, _external=True)

    # Send email
    send_reset_email(email, reset_link)

    return jsonify({'message': success_message}), 200


@app.route('/reset-mfa/confirm/<token>', methods=['GET', 'POST'])
def confirm_mfa_reset(token):
    """
    Confirm MFA reset using the token from the email link.
    GET: Validate token and show confirmation info.
    POST: Execute the MFA reset (disable MFA).
    """
    cleanup_expired_tokens()

    token_data = mfa_reset_tokens.get(token)

    if not token_data:
        return jsonify({'error': 'Invalid or expired reset token'}), 400

    if token_data['used']:
        return jsonify({'error': 'This reset token has already been used'}), 400

    if token_data['expires_at'] < datetime.utcnow():
        del mfa_reset_tokens[token]
        return jsonify({'error': 'Reset token has expired. Please request a new one.'}), 400

    email = token_data['email']
    user = users_db.get(email)

    if not user:
        return jsonify({'error': 'User account not found'}), 404

    if request.method == 'GET':
        # Show token validity info (for frontend to display confirmation page)
        return jsonify({
            'message': 'Valid reset token.',
            'email': email,
            'expires_at': token_data['expires_at'].isoformat(),
            'action': 'POST to this endpoint to confirm MFA reset'
        }), 200

    # POST: Execute the reset
    # Mark token as used
    token_data['used'] = True

    # Disable MFA
    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_backup_codes'] = []
    user['mfa_reset_count'] = user.get('mfa_reset_count', 0) + 1

    # Invalidate all other pending reset tokens for this user
    for t, d in mfa_reset_tokens.items():
        if d['email'] == email and t != token:
            d['used'] = True

    # Send notification email about MFA being disabled
    notification = {
        'to': email,
        'subject': 'MFA Has Been Disabled on Your Account',
        'body': (
            f'Multi-Factor Authentication has been disabled on your account '
            f'via the account recovery process.\n\n'
            f'You can now log in with just your email and password.\n\n'
            f'We strongly recommend re-enabling MFA after logging in.\n\n'
            f'If you did not perform this action, please change your password '
            f'immediately and contact support.'
        ),
        'timestamp': datetime.utcnow().isoformat()
    }
    email_outbox.append(notification)
    print(f"[EMAIL SENT] MFA disabled notification to: {email}")

    return jsonify({
        'message': 'MFA has been successfully disabled. You can now log in with your password.',
        'email': email,
        'recommendation': 'Please re-enable MFA after logging in for better security.'
    }), 200


@app.route('/reset-mfa/status/<token>', methods=['GET'])
def reset_token_status(token):
    """Check the status of a reset token."""
    token_data = mfa_reset_tokens.get(token)

    if not token_data:
        return jsonify({'valid': False, 'reason': 'Token not found'}), 404

    if token_data['used']:
        return jsonify({'valid': False, 'reason': 'Token already used'}), 400

    if token_data['expires_at'] < datetime.utcnow():
        return jsonify({'valid': False, 'reason': 'Token expired'}), 400

    return jsonify({
        'valid': True,
        'email': token_data['email'],
        'expires_at': token_data['expires_at'].isoformat()
    }), 200


